import { createContext, useState, useContext, ReactNode } from 'react';

interface ShowContextType {
  shows: any[];
  setShows: (shows: any[]) => void;
}

const ShowContext = createContext<ShowContextType | undefined>(undefined);

export const ShowProvider = ({ children }: { children: ReactNode }) => {
  const [shows, setShows] = useState<any[]>([]);

  return (
    <ShowContext.Provider value={{ shows, setShows }}>
      {children}
    </ShowContext.Provider>
  );
};

export const useShowContext = () => {
  const context = useContext(ShowContext);
  if (!context) {
    throw new Error('useShowContext must be used within a ShowProvider');
  }
  return context;
};
